import{_ as l,o,c as i,ag as a}from"./chunks/framework.DXGyWiRo.js";const q=JSON.parse('{"title":"知识点1：数据、信息与知识","description":"","frontmatter":{"title":"知识点1：数据、信息与知识"},"headers":[],"relativePath":"high-school-it/knowledge-1.md","filePath":"high-school-it/knowledge-1.md"}'),e={name:"high-school-it/knowledge-1.md"};function r(d,t,n,u,h,s){return o(),i("div",null,[...t[0]||(t[0]=[a('<h1 id="知识点1-数据、信息与知识" tabindex="-1">知识点1：数据、信息与知识 <a class="header-anchor" href="#知识点1-数据、信息与知识" aria-label="Permalink to &quot;知识点1：数据、信息与知识&quot;">​</a></h1><h2 id="一、数据" tabindex="-1">一、数据 <a class="header-anchor" href="#一、数据" aria-label="Permalink to &quot;一、数据&quot;">​</a></h2><p><strong>定义</strong>：数据是反映客观事物运动状态的原始事实，是离散的、未经组织的符号。</p><p><strong>书中的例子</strong>：</p><ul><li>共享单车数据：包含 bike_id（单车编号）、datetime（开锁时间）、temp_value（气温）、wind_speed（风速）等原始记录</li><li>传感器数据：通过可穿戴设备采集的温度、脉搏、心电图等</li></ul><p><strong>通俗理解 - 验血报告</strong>：</p><blockquote><p>验血报告上各项指标的原始数值：</p><ul><li>血糖：5.6 mmol/L</li><li>白细胞：7.2×10⁹/L</li><li>血红蛋白：138 g/L</li></ul><p>——这些数字本身，告诉你&quot;是什么&quot;，但不知道是否正常</p></blockquote><hr><h2 id="二、信息" tabindex="-1">二、信息 <a class="header-anchor" href="#二、信息" aria-label="Permalink to &quot;二、信息&quot;">​</a></h2><p><strong>定义</strong>：信息是经过组织、处理具有意义的数据，是对数据的解释。</p><p><strong>书中的例子</strong>：</p><ul><li>将采集到的共享单车原始数据经过&quot;整理&quot;（去除重复、缺失、异常值）后，得到有意义的数据集</li></ul><p><strong>通俗理解 - 验血报告</strong>：</p><blockquote><p>当医生告诉你：</p><ul><li>&quot;你的血糖偏高，正常应该低于5.1&quot;</li><li>&quot;白细胞偏高，可能有炎症&quot;</li></ul><p>——这是对数据的解释，有了具体意义</p></blockquote><hr><h2 id="三、知识" tabindex="-1">三、知识 <a class="header-anchor" href="#三、知识" aria-label="Permalink to &quot;三、知识&quot;">​</a></h2><p><strong>定义</strong>：知识是系统化的信息，是人类在实践基础上对客观事物本质规律的认识。</p><p><strong>书中的例子</strong>：</p><ul><li>通过对共享单车数据的长期分析，发现&quot;工作日与周末骑行规律不同&quot;——这是一种知识</li></ul><p><strong>通俗理解 - 验血报告</strong>：</p><blockquote><p>医生基于医学知识进一步判断：</p><ul><li>&quot;血糖持续偏高+家族史+腹型肥胖=糖尿病高风险，需要生活方式干预&quot;</li></ul><p>——这是从大量病例中归纳出的规律，可以预测、预防、指导决策</p></blockquote><hr><h2 id="四、总结" tabindex="-1">四、总结 <a class="header-anchor" href="#四、总结" aria-label="Permalink to &quot;四、总结&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>特点</th><th>验血报告例子</th></tr></thead><tbody><tr><td>数据</td><td>原始数值</td><td>&quot;血糖5.6&quot;</td></tr><tr><td>信息</td><td>数据+解释</td><td>&quot;血糖偏高，正常&lt;5.1&quot;</td></tr><tr><td>知识</td><td>规律+预判</td><td>&quot;高血糖+肥胖→糖尿病风险&quot;</td></tr></tbody></table><p><strong>核心要点</strong>：数字化学习过程中，学生需要体验从数据到信息、从信息到知识的转化过程，体会数字化技术发展对社会发展和个人成长的影响。</p><h2 id="五、真题" tabindex="-1">五、真题 <a class="header-anchor" href="#五、真题" aria-label="Permalink to &quot;五、真题&quot;">​</a></h2><ol><li><p>人工智能的发展离不开数据。小申从网上了解到，2017-2025年全球数据总量的增长趋势及预测情况（如图所示）。关于数据、信息与知识，以下说法正确的是（ ）（单选题，2分）</p><ul><li>A. 这张图属于知识， “170” 属于数据</li><li>B. 小申将这张图分享给其他同学，会产生信息损耗</li><li>C. 图中的信息对所有人产生的价值是相同的</li><li>D. “2025年全球数据总量约170ZB” 属于信息</li></ul></li><li><p>生成式人工智能可以生成诗歌、图像等。小申与同学们就生成式人工智能展开关于数据、信息与知识的讨论，以下描述正确的是（ ）（单选题，2分）</p><ul><li>A. 生成式人工智能生成的图像是信息</li><li>B. 生成式人工智能生成的所有内容都是知识</li><li>C. 生成式人工智能可以处理不同表现形式的数据</li></ul></li><li><p>对机器狗发现的未知昆虫，生物学家进一步研究其形态特征、遗传信息和生活习性等，经过严谨论证，最终将其确认为一种新物种。这一发现也得到该领域专家与从业人员的一致认可。有关该新物种认识和经验的总和属于（ ）。（单选题，2分）</p><ul><li>A. 数据</li><li>B. 知识</li><li>C. 消息</li><li>D. 信息</li></ul></li></ol><h3 id="答案" tabindex="-1">答案 <a class="header-anchor" href="#答案" aria-label="Permalink to &quot;答案&quot;">​</a></h3><ol><li>A</li><li>C</li><li>B</li></ol>',29)])])}const c=l(e,[["render",r]]);export{q as __pageData,c as default};
